    const activeDeliveries = allOrders.filter(o => o.status === "in_transit").length;
    const completedDeliveries = allOrders.filter(o => o.status === "delivered").length;

    return {
      patients,
      pharmaciens,
      livreurs,
      orders,
      pendingOrders,
      activeDeliveries,
