import { useState, useRef, useEffect } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { captureFromCamera } from "@/lib/camera";

export default function Camera() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isFlashOn, setIsFlashOn] = useState(false);

  useEffect(() => {
    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment' },
        audio: false
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (error) {
      console.error('Error accessing camera:', error);
      toast({
        title: "Erreur de caméra",
        description: "Impossible d'accéder à la caméra",
        variant: "destructive",
      });
    }
  };

  const uploadPrescriptionMutation = useMutation({
    mutationFn: async (imageBlob: Blob) => {
      const formData = new FormData();
      formData.append('prescription', imageBlob, 'prescription.jpg');
      return apiRequest('POST', '/api/prescriptions', formData);
    },
    onSuccess: () => {
      toast({
        title: "Photo capturée",
        description: "Photo sauvegardée avec succès",
      });
      // Ne pas rediriger automatiquement - laisser l'utilisateur continuer
      goBack();
    },
    onError: (error) => {
      toast({
        title: "Erreur",
        description: "Impossible d'enregistrer la photo",
        variant: "destructive",
      });
    },
  });

  const capturePhoto = async () => {
    if (!videoRef.current) return;

    try {
      const imageBlob = await captureFromCamera(videoRef.current);
      uploadPrescriptionMutation.mutate(imageBlob);
    } catch (error) {
      toast({
        title: "Erreur de capture",
        description: "Impossible de prendre la photo",
        variant: "destructive",
      });
    }
  };

  const toggleFlash = () => {
    setIsFlashOn(!isFlashOn);
    // Note: Flash control is limited in web browsers
    // This would typically require native app functionality
  };

  const goBack = () => {
    window.history.back();
  };

  return (
    <div className="min-h-screen bg-black relative">
      {/* Header */}
      <div className="absolute top-0 left-0 right-0 z-10 p-4">
        <div className="flex items-center justify-between">
          <Button
            variant="ghost"
            size="icon"
            onClick={goBack}
            className="w-10 h-10 bg-black/30 backdrop-blur-sm rounded-full text-white hover:bg-black/50"
            data-testid="button-back"
          >
            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" />
            </svg>
          </Button>
          <h2 className="text-white font-semibold" data-testid="text-camera-title">
            Scanner l'ordonnance
          </h2>
          <Button
            variant="ghost"
            size="icon"
            onClick={toggleFlash}
            className={`w-10 h-10 backdrop-blur-sm rounded-full text-white hover:bg-white/30 ${isFlashOn ? 'bg-white/30' : 'bg-black/30'}`}
            data-testid="button-flash"
          >
            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" />
            </svg>
          </Button>
        </div>
      </div>

      {/* Camera Preview */}
      <div className="h-screen bg-gray-900 flex items-center justify-center">
        {stream ? (
          <video
            ref={videoRef}
            autoPlay
            playsInline
            className="w-full h-full object-cover"
            data-testid="video-camera-preview"
          />
        ) : (
          <div className="text-center text-white">
            <svg className="w-16 h-16 mx-auto mb-4 opacity-50" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" />
            </svg>
            <p className="text-lg font-medium mb-2">Caméra en cours de chargement...</p>
            <p className="text-white/70 text-sm">Préparation de la capture</p>
          </div>
        )}
      </div>

      {/* Camera Overlay Guide */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="w-80 h-60 border-4 border-white rounded-2xl border-dashed opacity-50"></div>
      </div>

      {/* Bottom Controls */}
      <div className="absolute bottom-0 left-0 right-0 p-6">
        <div className="flex items-center justify-center space-x-8">
          <Button
            variant="ghost"
            size="icon"
            className="w-14 h-14 bg-white/20 backdrop-blur-sm rounded-full text-white hover:bg-white/30"
            data-testid="button-gallery"
          >
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" />
            </svg>
          </Button>

          <Button
            onClick={capturePhoto}
            disabled={uploadPrescriptionMutation.isPending}
            className="w-20 h-20 bg-white rounded-full hover:bg-gray-100 shadow-lg"
            data-testid="button-capture"
          >
            <div className="w-16 h-16 bg-pharma-green rounded-full flex items-center justify-center">
              {uploadPrescriptionMutation.isPending ? (
                <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              ) : (
                <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" />
                </svg>
              )}
            </div>
          </Button>

          <Button
            variant="ghost"
            size="icon"
            className="w-14 h-14 bg-white/20 backdrop-blur-sm rounded-full text-white hover:bg-white/30"
            data-testid="button-switch-camera"
          >
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20">
              <path d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" />
            </svg>
          </Button>
        </div>
        <p className="text-white text-center mt-4 text-sm" data-testid="text-camera-instruction">
          Positionnez l'ordonnance dans le cadre
        </p>
      </div>
    </div>
  );
}

client/src/pages/create-pharmacy.tsx.content:
import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { apiRequest } from "@/lib/queryClient";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { ArrowLeft, MapPin, Phone, Clock } from "lucide-react";
import { useLocation } from "wouter";

export default function CreatePharmacy() {
  const [location, navigate] = useLocation();
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [pharmacyData, setPharmacyData] = useState({
    name: `Pharmacie ${user?.firstName} ${user?.lastName}`,
    address: user?.address || 'Abidjan, Côte d\'Ivoire',
    phone: user?.phone || '',
    deliveryTime: '30',
    deliveryRadius: '5',
    minDeliveryFee: '1000'
  });

  const createPharmacyMutation = useMutation({
    mutationFn: async (data: any) => {
      // First create the pharmacy
      const pharmacyResponse = await apiRequest('POST', '/api/pharmacies', {
        ...data,
        latitude: 5.2893 + (Math.random() - 0.5) * 0.1,
        longitude: -3.9882 + (Math.random() - 0.5) * 0.1,
        rating: 4.5,
        isOpen: true,
        openingHours: {
          monday: { open: '08:00', close: '19:00' },
          tuesday: { open: '08:00', close: '19:00' },
          wednesday: { open: '08:00', close: '19:00' },
          thursday: { open: '08:00', close: '19:00' },
          friday: { open: '08:00', close: '19:00' },
          saturday: { open: '08:00', close: '17:00' },
          sunday: { open: '09:00', close: '15:00' }
        }
      });

      const pharmacy = await pharmacyResponse.json();

      // Then update the user to associate with the pharmacy
      await apiRequest('PUT', '/api/auth/user', {
        pharmacyId: pharmacy.id
      });

      return pharmacy;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pharmacies/my-pharmacy'] });
      queryClient.invalidateQueries({ queryKey: ['/api/auth/user'] });
      toast({ 
        title: "Pharmacie créée", 
        description: "Votre pharmacie a été créée avec succès." 
      });
      navigate('/pharmacy-profile');
    },
    onError: (error) => {
      console.error('Error creating pharmacy:', error);
      toast({ 
        title: "Erreur", 
        description: "Impossible de créer la pharmacie. Veuillez réessayer.", 
        variant: "destructive" 
      });
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!pharmacyData.name || !pharmacyData.address || !pharmacyData.phone) {
      toast({
        title: "Champs requis",
        description: "Veuillez remplir tous les champs obligatoires.",
        variant: "destructive"
      });
      return;
    }

    createPharmacyMutation.mutate(pharmacyData);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center gap-3">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => navigate('/dashboard-pharmacien')}
            >
              <ArrowLeft className="h-4 w-4" />
            </Button>
            <div>
              <h1 className="text-xl font-bold">Créer votre Pharmacie</h1>
              <p className="text-sm text-gray-600">Configurez les informations de votre établissement</p>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-2xl mx-auto p-4">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MapPin className="h-5 w-5 text-blue-600" />
              Informations de la Pharmacie
            </CardTitle>
            <CardDescription>
              Renseignez les détails de votre pharmacie pour que les patients puissent vous trouver
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="name" className="text-sm font-medium">
                  Nom de la pharmacie *
                </Label>
                <Input
                  id="name"
                  value={pharmacyData.name}
                  onChange={(e) => setPharmacyData(prev => ({ ...prev, name: e.target.value }))}
                  placeholder="Ex: Pharmacie de la Paix"
                  className="w-full"
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="address" className="text-sm font-medium">
                  Adresse complète *
                </Label>
                <Textarea
                  id="address"
                  value={pharmacyData.address}
                  onChange={(e) => setPharmacyData(prev => ({ ...prev, address: e.target.value }))}
                  placeholder="Ex: Boulevard de la Paix, Cocody, Abidjan"
                  className="w-full"
                  rows={3}
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="phone" className="text-sm font-medium">
                  Numéro de téléphone *
                </Label>
                <Input
                  id="phone"
                  type="tel"
                  value={pharmacyData.phone}
                  onChange={(e) => setPharmacyData(prev => ({ ...prev, phone: e.target.value }))}
                  placeholder="Ex: +225 27 22 44 55 66"
                  className="w-full"
                  required
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="deliveryTime" className="text-sm font-medium">
                    Temps de livraison (min)
                  </Label>
                  <Input
                    id="deliveryTime"
                    type="number"
                    value={pharmacyData.deliveryTime}
                    onChange={(e) => setPharmacyData(prev => ({ ...prev, deliveryTime: e.target.value }))}
                    placeholder="30"
                    min="10"
                    max="120"
                    className="w-full"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="deliveryRadius" className="text-sm font-medium">
                    Zone de livraison (km)
                  </Label>
                  <Input
                    id="deliveryRadius"
                    type="number"
                    value={pharmacyData.deliveryRadius}
                    onChange={(e) => setPharmacyData(prev => ({ ...prev, deliveryRadius: e.target.value }))}
                    placeholder="5"
                    min="1"
                    max="50"
                    className="w-full"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="minDeliveryFee" className="text-sm font-medium">
                    Frais de livraison (FCFA)
                  </Label>
                  <Input
                    id="minDeliveryFee"
                    type="number"
                    value={pharmacyData.minDeliveryFee}
                    onChange={(e) => setPharmacyData(prev => ({ ...prev, minDeliveryFee: e.target.value }))}
                    placeholder="1000"
                    min="0"
                    className="w-full"
                  />
                </div>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                <div className="flex items-start gap-3">
                  <Clock className="h-5 w-5 text-blue-600 mt-0.5" />
                  <div>
                    <h4 className="font-medium text-blue-900 mb-1">Horaires d'ouverture</h4>
                    <p className="text-sm text-blue-700">
                      Les horaires par défaut seront configurés (8h-19h en semaine, 8h-17h le samedi, 9h-15h le dimanche).
                      Vous pourrez les modifier après la création dans le profil de la pharmacie.
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => navigate('/dashboard-pharmacien')}
                  className="flex-1"
                >
                  Annuler
                </Button>
                <Button
                  type="submit"
                  disabled={createPharmacyMutation.isPending}
                  className="flex-1"
                >
                  {createPharmacyMutation.isPending ? 'Création...' : 'Créer ma pharmacie'}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/pages/dashboard-livreur.tsx.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { apiRequest } from "@/lib/queryClient";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import BottomNavigation from "@/components/bottom-navigation";

export default function DashboardLivreur() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState("my-deliveries");
  const [isAvailable, setIsAvailable] = useState(true);
  const [selectedOrder, setSelectedOrder] = useState<any>(null);

  // Récupérer les commandes assignées à ce livreur
  const { data: myDeliveries, isLoading: loadingMyDeliveries } = useQuery({
    queryKey: ["/api/livreur/deliveries"],
    enabled: true,
    select: (data) => {
      // Filter deliveries that are assigned to this user
      return data?.filter((delivery: any) => 
        delivery.deliveryPersonId === user?.id && 
        (delivery.status === 'ready_for_delivery' || 
         delivery.status === 'in_delivery' || 
         delivery.status === 'delivered')
      ) || [];
    }
  });

  // Récupérer les livraisons disponibles
  const { data: availableDeliveries, isLoading: loadingAvailable } = useQuery({
    queryKey: ["/api/livreur/available-deliveries"],
    enabled: isAvailable
  });

  // Récupérer les notifications
  const { data: notifications } = useQuery({
    queryKey: ["/api/notifications"],
    enabled: true
  });

  // Mutation pour accepter une livraison
  const acceptDeliveryMutation = useMutation({
    mutationFn: (orderId: string) =>
      apiRequest("POST", `/api/livreur/deliveries/${orderId}/accept`),
    onSuccess: () => {
      toast({
        title: "Livraison acceptée",
        description: "Vous pouvez maintenant effectuer cette livraison",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/livreur/deliveries"] });
      queryClient.invalidateQueries({ queryKey: ["/api/livreur/available-deliveries"] });
    },
    onError: () => {
      toast({
        title: "Erreur",
        description: "Impossible d'accepter cette livraison",
        variant: "destructive",
      });
    },
  });

  // Mutation pour mettre à jour le statut d'une livraison
  const updateDeliveryMutation = useMutation({
    mutationFn: ({ orderId, status }: { orderId: string; status: string }) =>
      apiRequest("POST", `/api/livreur/deliveries/${orderId}/status`, { status }),
    onSuccess: (data, variables) => {
      toast({
        title: "Statut mis à jour",
        description: variables.status === 'delivered' ? "Livraison terminée avec succès !" : "Le statut de la livraison a été mis à jour",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/livreur/deliveries"] });
    },
    onError: () => {
      toast({
        title: "Erreur",
        description: "Impossible de mettre à jour le statut",
        variant: "destructive",
      });
    },
  });

  const handleAcceptDelivery = (orderId: string) => {
    acceptDeliveryMutation.mutate(orderId);
  };

  const handleUpdateDeliveryStatus = (orderId: string, status: string) => {
    updateDeliveryMutation.mutate({ orderId, status });
  };

  if (loadingMyDeliveries && loadingAvailable) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6 pb-24">
      <div className="max-w-6xl mx-auto">
        <div className="mb-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-blue-600 mb-2">
                🚚 Tableau de bord Livreur
              </h1>
              <p className="text-gray-600">
                Bienvenue {user?.firstName} ! Gérez vos livraisons
              </p>
            </div>
          </div>
        </div>

        {/* Résumé des notifications */}
        {notifications && notifications.length > 0 && (
          <Card className="mb-6 bg-purple-50 border-purple-200">
            <CardContent className="p-4">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                  🔔
                </div>
                <div>
                  <h3 className="font-semibold text-purple-800">Nouvelles notifications</h3>
                  <p className="text-sm text-purple-600">
                    {notifications.filter((n: any) => !n.isRead).length} nouvelles notifications
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Statut de Disponibilité */}
        <Card className="mb-6">
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center ${
                  isAvailable ? 'bg-green-100' : 'bg-gray-100'
                }`}>
                  {isAvailable ? '🟢' : '🔴'}
                </div>
                <div>
                  <h3 className="font-semibold text-lg">
                    {isAvailable ? 'Disponible pour Livraisons' : 'Indisponible'}
                  </h3>
                  <p className="text-sm text-gray-600">
                    {isAvailable 
                      ? 'Vous recevrez des missions de livraison' 
                      : 'Activez pour recevoir des missions'
                    }
                  </p>
                </div>
              </div>
              <Switch
                checked={isAvailable}
                onCheckedChange={setIsAvailable}
              />
            </div>
          </CardContent>
        </Card>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="my-deliveries">
              Mes Livraisons
              {myDeliveries && myDeliveries.length > 0 && (
                <Badge variant="default" className="ml-2 bg-purple-600">
                  {myDeliveries.length}
                </Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="available">
              Missions Disponibles
              {availableDeliveries && availableDeliveries.length > 0 && (
                <Badge variant="destructive" className="ml-2">
                  {availableDeliveries.length}
                </Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="earnings">Mes Gains</TabsTrigger>
          </TabsList>

          {/* Mes Livraisons Assignées */}
          <TabsContent value="my-deliveries" className="space-y-4">
            {!myDeliveries || myDeliveries.length === 0 ? (
              <div className="border rounded-lg p-6 bg-gray-50 text-center">
                <div className="text-gray-400 text-4xl mb-2">📦</div>
                <h3 className="font-semibold mb-2">Aucune livraison disponible</h3>
                <p className="text-sm text-gray-600">
                  Les commandes assignées ou disponibles apparaîtront ici
                </p>
                <div className="mt-4 text-xs text-gray-500">
                  <p>Statut de connexion: {user ? 'Connecté' : 'Déconnecté'}</p>
                  <p>ID utilisateur: {user?.id?.slice(0, 8)}...</p>
                </div>
              </div>
            ) : (
              myDeliveries.map((delivery: any) => (
                <Card key={delivery.id} className="border-l-4 border-l-purple-500">
                  <CardHeader>
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-lg">
                        Commande #{delivery.id.slice(0, 8)}
                      </CardTitle>
                      <Badge variant={
                        delivery.status === 'in_delivery' ? 'default' : 
                        delivery.status === 'delivered' ? 'secondary' : 
                        delivery.status === 'ready_for_delivery' && delivery.deliveryPersonId === user?.id ? 'outline' : 'destructive'
                      }>
                        {delivery.status === 'in_delivery' ? 'En livraison' : 
                         delivery.status === 'delivered' ? 'Livrée' : 
                         delivery.status === 'ready_for_delivery' && delivery.deliveryPersonId === user?.id ? 'Assignée' : 'En attente'}
                      </Badge>
                    </div>
                    <CardDescription>
                      {delivery.pharmacy?.name || 'Pharmacie inconnue'}
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    {/* Informations Patient */}
                    <div className="bg-blue-50 p-4 rounded-lg">
                      <h4 className="font-semibold text-blue-800 mb-2 flex items-center">
                        👤 Information Patient
                      </h4>
                      <p className="text-sm text-blue-700">
                        <strong>Nom:</strong> {delivery.patient?.firstName} {delivery.patient?.lastName}
                      </p>
                      <p className="text-sm text-blue-700">
                        <strong>Téléphone:</strong> {delivery.patient?.phone}
                      </p>
                    </div>

                    {/* Adresse de Livraison */}
                    <div className="bg-green-50 p-4 rounded-lg">
                      <h4 className="font-semibold text-green-800 mb-2 flex items-center">
                        📍 Adresse de Livraison
                      </h4>
                      <p className="text-sm text-green-700">{delivery.deliveryAddress}</p>
                    </div>

                    {/* Informations de Livraison (sans détails médicaments) */}
                    <div className="bg-yellow-50 p-4 rounded-lg">
                      <h4 className="font-semibold text-yellow-800 mb-2 flex items-center">
                        💊 Livraison Médicaments
                      </h4>
                      <p className="text-sm text-yellow-700">
                        <strong>Nombre d'articles:</strong> {delivery.medications?.length || 0} médicament(s)
                      </p>
                      <p className="text-sm text-yellow-700">
                        <strong>Type:</strong> Prescription médicale confidentielle
                      </p>
                      <Separator className="my-2" />
                      <div className="flex justify-between font-bold">
                        <span>Montant à collecter:</span>
                        <span>{delivery.totalAmount || 0} FCFA</span>
                      </div>
                    </div>

                    {/* Actions */}
                    <div className="flex gap-2">
                      {delivery.status === 'ready_for_delivery' && delivery.deliveryPersonId === user?.id && (
                        <Button
                          onClick={() => handleUpdateDeliveryStatus(delivery.id, 'in_delivery')}
                          className="flex-1 bg-blue-600 hover:bg-blue-700"
                          disabled={updateDeliveryMutation.isPending}
                        >
                          Commencer la Livraison 🚀
                        </Button>
                      )}
                      {delivery.status === 'in_delivery' && (
                        <div className="flex-1 bg-blue-50 border border-blue-200 rounded-md p-3 text-center">
                          <p className="text-sm text-blue-700 font-medium">
                            🏠 Livraison en cours
                          </p>
                          <p className="text-xs text-blue-600 mt-1">
                            Le patient confirmera la réception
                          </p>
                        </div>
                      )}
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button 
                            variant="outline" 
                            onClick={() => setSelectedOrder(delivery)}
                            className="flex-1"
                          >
                            Voir Détails
                          </Button>
                        </DialogTrigger>
                        <DialogContent className="max-w-2xl">
                          <DialogHeader>
                            <DialogTitle>Détails de la Commande #{delivery.id.slice(0, 8)}</DialogTitle>
                            <DialogDescription>
                              Informations complètes de la livraison
                            </DialogDescription>
                          </DialogHeader>
                          <div className="space-y-4">
                            <div>
                              <Label>Statut</Label>
                              <Badge className="ml-2">
                                {delivery.status === 'in_delivery' ? 'En livraison' : 
                                 delivery.status === 'delivered' ? 'Livrée' : 
                                 delivery.status === 'ready_for_delivery' && delivery.deliveryPersonId === user?.id ? 'Assignée' : 'En attente'}
                              </Badge>
                            </div>
                            <div>
                              <Label>Patient</Label>
                              <p>{delivery.patient?.firstName} {delivery.patient?.lastName}</p>
                              <p className="text-sm text-gray-600">{delivery.patient?.phone}</p>
                            </div>
                            <div>
                              <Label>Adresse</Label>
                              <p>{delivery.deliveryAddress}</p>
                            </div>
                            <div>
                              <Label>Pharmacie</Label>
                              <p>{delivery.pharmacy?.name}</p>
                              <p className="text-sm text-gray-600">{delivery.pharmacy?.phone}</p>
                            </div>
                          </div>
                        </DialogContent>
                      </Dialog>
                    </div>
                  </CardContent>
                </Card>
              ))
            )}
          </TabsContent>

          {/* Missions Disponibles */}
          <TabsContent value="available" className="space-y-4">
            {!availableDeliveries || availableDeliveries.length === 0 ? (
              <Card>
                <CardContent className="p-8 text-center">
                  <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                    🚴
                  </div>
                  <h3 className="text-lg font-semibold text-gray-700 mb-2">
                    Aucune mission disponible
                  </h3>
                  <p className="text-gray-500">
                    Les nouvelles missions apparaîtront ici
                  </p>
                </CardContent>
              </Card>
            ) : (
              availableDeliveries.map((delivery: any) => (
                <Card key={delivery.id} className="border-l-4 border-l-orange-500">
                  <CardHeader>
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-lg">
                        Mission #{delivery.id.slice(0, 8)}
                      </CardTitle>
                      <Badge variant="destructive">
                        Disponible
                      </Badge>
                    </div>
                    <CardDescription>
                      {delivery.pharmacy?.name} • +500 FCFA
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <Label className="text-sm font-medium text-gray-600">Distance</Label>
                        <p className="text-sm">≈ 2-5 km</p>
                      </div>
                      <div>
                        <Label className="text-sm font-medium text-gray-600">Montant</Label>
                        <p className="text-sm font-semibold">{delivery.totalAmount || 0} FCFA</p>
                      </div>
                    </div>
                    <div>
                      <Label className="text-sm font-medium text-gray-600">Adresse de livraison</Label>
                      <p className="text-sm">{delivery.deliveryAddress}</p>
                    </div>
                    <Button
                      onClick={() => handleAcceptDelivery(delivery.id)}
                      className="w-full bg-orange-600 hover:bg-orange-700"
                      disabled={acceptDeliveryMutation.isPending}
                    >
                      Accepter cette Mission 🚴
                    </Button>
                  </CardContent>
                </Card>
              ))
            )}
          </TabsContent>

          {/* Gains */}
          <TabsContent value="earnings">
            <Card>
              <CardHeader>
                <CardTitle>💰 Mes Gains</CardTitle>
                <CardDescription>
                  Historique de vos revenus de livraison
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-green-50 p-4 rounded-lg">
                    <h4 className="font-semibold text-green-800">Gains Aujourd'hui</h4>
                    <p className="text-2xl font-bold text-green-600">
                      {myDeliveries ? myDeliveries.filter((d: any) => 
                        d.status === 'delivered' && 
                        new Date(d.deliveredAt || d.updatedAt).toDateString() === new Date().toDateString()
                      ).length * 500 : 0} FCFA
                    </p>
                  </div>
                  <div className="bg-blue-50 p-4 rounded-lg">
                    <h4 className="font-semibold text-blue-800">Total Livraisons</h4>
                    <p className="text-2xl font-bold text-blue-600">
                      {myDeliveries ? myDeliveries.filter((d: any) => d.status === 'delivered').length : 0}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>

      <BottomNavigation />
    </div>
  );
}

