              <div className="w-12 h-12 bg-gray-100 rounded-lg mx-auto mb-3 flex items-center justify-center">
                <svg className="w-6 h-6 text-gray-400" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" />
                </svg>
              </div>
              <p className="text-gray-600 font-medium">Téléverser l'ordonnance</p>
            </button>

            <div className="space-y-4">
              <div>
                <h3 className="font-semibold text-gray-900 mb-2">
                  Sélectionner une pharmacie
                </h3>
                <p className="text-gray-600 text-sm">
                  Veuillez sélectionner une pharmacie
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Button
          className="w-full max-w-sm bg-pharma-blue text-white py-4 rounded-xl font-semibold text-lg h-auto hover:bg-pharma-blue/90"
          onClick={handleContinue}
          data-testid="button-continue"
        >
          Continuer
        </Button>
      </div>
    </div>
  );
}

client/src/pages/order-validation.tsx.content:
import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { useLocation, useSearch } from "wouter";
import { apiRequest } from "@/lib/queryClient";
import { ArrowLeft, Trash2, ShoppingCart, CreditCard, X } from "lucide-react";

interface Medication {
  name: string;
  available: boolean;
  surBon: boolean;
  price: number;
  selected?: boolean;
}

export default function OrderValidationPage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [location, navigate] = useLocation();
  const searchParams = useSearch();

  // Get order ID from URL
  const orderId = new URLSearchParams(searchParams).get('orderId');

  console.log('Order validation - URL:', location, 'orderId:', orderId);

  const [selectedMedications, setSelectedMedications] = useState<Record<string, boolean>>({});
  const [paymentMethod, setPaymentMethod] = useState<string>('');
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Fetch order details
  const { data: order, isLoading } = useQuery({
    queryKey: [`/api/orders/${orderId}`],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/orders/${orderId}`);
      return response.json();
    },
    enabled: !!orderId
  });

  // Initialize selected medications when order data loads
  useEffect(() => {
    if (order?.medications) {
      const medications = typeof order.medications === 'string' 
        ? JSON.parse(order.medications) 
        : order.medications;

      const initialSelection: Record<string, boolean> = {};
      medications.forEach((med: Medication, index: number) => {
        if (med.available) {
          initialSelection[`${med.name}-${index}`] = true;
        }
      });
      setSelectedMedications(initialSelection);
    }
  }, [order]);

  // Calculate total price
  const calculateTotal = () => {
    if (!order?.medications) return 0;

    const medications = typeof order.medications === 'string' 
      ? JSON.parse(order.medications) 
      : order.medications;

    return medications.reduce((total: number, med: Medication, index: number) => {
      const key = `${med.name}-${index}`;
      if (selectedMedications[key] && med.available && med.price) {
        return total + med.price;
      }
      return total;
    }, 0);
  };

  const subtotal = calculateTotal();
  const deliveryFee = 1000;
  const grandTotal = subtotal + deliveryFee;

  // Toggle medication selection
  const toggleMedication = (medicationKey: string) => {
    setSelectedMedications(prev => ({
      ...prev,
      [medicationKey]: !prev[medicationKey]
    }));
  };

  // Payment mutation
  const paymentMutation = useMutation({
    mutationFn: (paymentData: any) =>
      apiRequest("POST", "/api/orders/payment", paymentData),
    onSuccess: () => {
      toast({
        title: "Paiement confirmé",
        description: "Votre commande est maintenant en cours de livraison",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/orders"] });
      navigate('/dashboard-patient');
    },
    onError: () => {
      toast({
        title: "Erreur de paiement",
        description: "Impossible de traiter le paiement. Veuillez réessayer.",
        variant: "destructive",
      });
    },
  });

  // Cancel order mutation
  const cancelOrderMutation = useMutation({
    mutationFn: () => apiRequest("POST", `/api/orders/${orderId}/cancel`),
    onSuccess: () => {
      toast({
        title: "Commande annulée",
        description: "Votre commande a été annulée avec succès",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/orders"] });
      navigate('/dashboard-patient');
    },
    onError: () => {
      toast({
        title: "Erreur",
        description: "Impossible d'annuler la commande",
        variant: "destructive",
      });
    },
  });

  const handlePayment = () => {
    if (!paymentMethod) {
      toast({
        title: "Méthode de paiement requise",
        description: "Veuillez sélectionner un moyen de paiement",
        variant: "destructive",
      });
      return;
    }

    if (subtotal === 0) {
      toast({
        title: "Sélection requise",
        description: "Veuillez sélectionner au moins un médicament",
        variant: "destructive",
      });
      return;
    }

    const paymentData = {
      orderId: order.id,
      paymentMethod,
      amount: grandTotal,
      deliveryFee: deliveryFee,
      selectedMedications: Object.keys(selectedMedications).filter(key => selectedMedications[key])
    };

    paymentMutation.mutate(paymentData);
  };

  const handleCancelOrder = () => {
    if (confirm('Êtes-vous sûr de vouloir annuler cette commande ?')) {
      cancelOrderMutation.mutate();
    }
  };

  const getPaymentMethods = () => {
    return [
      { id: 'wave', name: 'WAVE CI', number: '+225 0701234567', color: 'bg-blue-600' },
      { id: 'orange', name: 'Orange Money', number: '+225 0701234568', color: 'bg-orange-600' },
      { id: 'moov', name: 'Moov Money', number: '+225 0501234567', color: 'bg-purple-600' },
      { id: 'momo', name: 'MTN MoMo', number: '+225 0501234568', color: 'bg-yellow-600' }
    ];
  };

  if (!orderId) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <Card className="w-full max-w-md">
          <CardContent className="text-center py-8">
            <p className="text-gray-600 mb-4">Commande non trouvée</p>
            <Button onClick={() => navigate('/dashboard-patient')}>
              Retour au tableau de bord
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p>Chargement des détails de la commande...</p>
        </div>
      </div>
    );
  }

  const medications = order?.medications ? 
    (typeof order.medications === 'string' ? JSON.parse(order.medications) : order.medications) : [];

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-4xl mx-auto p-4">
        {/* Header */}
        <div className="flex items-center gap-4 mb-6">
          <Button 
            variant="ghost" 
            size="sm" 
            onClick={() => navigate('/dashboard-patient')}
            className="flex items-center gap-2"
          >
            <ArrowLeft className="h-4 w-4" />
            Retour
          </Button>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">
              Validation de la commande
            </h1>
            <p className="text-gray-600">
              Commande #{order?.id?.slice(0, 8)} - {order?.pharmacy?.name}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Medications List */}
          <div className="lg:col-span-2 space-y-4">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <ShoppingCart className="h-5 w-5" />
                  Médicaments disponibles
                </CardTitle>
                <CardDescription>
                  Sélectionnez les médicaments que vous souhaitez commander
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {medications.map((med: Medication, index: number) => {
                    const key = `${med.name}-${index}`;
                    const isSelected = selectedMedications[key] || false;

                    return (
                      <div 
                        key={index}
                        className={`border rounded-lg p-4 transition-all ${
                          med.available 
                            ? isSelected 
                              ? 'border-blue-500 bg-blue-50' 
                              : 'border-gray-200 hover:border-gray-300'
                            : 'border-red-200 bg-red-50'
                        }`}
                      >
                        <div className="flex items-start justify-between">
                          <div className="flex items-start gap-3 flex-1">
                            {med.available && (
                              <Checkbox
                                checked={isSelected}
                                onCheckedChange={() => toggleMedication(key)}
                                className="mt-1"
                              />
                            )}
                            <div className="flex-1">
                              <div className="flex items-center gap-2 mb-2">
                                <h4 className="font-medium text-gray-900">{med.name}</h4>
                                {med.surBon && (
                                  <Badge variant="outline" className="text-xs">
                                    Sur BON
                                  </Badge>
                                )}
                              </div>

                              <div className="flex items-center gap-4">
                                <Badge 
                                  variant={med.available ? "default" : "destructive"}
                                  className="text-xs"
                                >
                                  {med.available ? "Disponible" : "Indisponible"}
                                </Badge>

                                {med.available && med.price && (
                                  <span className="text-lg font-semibold text-green-600">
                                    {med.price.toLocaleString()} FCFA
                                  </span>
                                )}
                              </div>

                              {!med.available && (
                                <p className="text-sm text-red-600 mt-1">
                                  Ce médicament n'est pas disponible actuellement
                                </p>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Order Summary */}
          <div className="space-y-4">
            <Card className="sticky top-4">
              <CardHeader>
                <CardTitle className="text-lg">Récapitulatif</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* Pharmacy Info */}
                <div className="pb-4 border-b">
                  <p className="text-sm text-gray-600">Pharmacie</p>
                  <p className="font-medium">{order?.pharmacy?.name}</p>
                  <p className="text-xs text-gray-500 mt-1">{order?.deliveryAddress}</p>
                </div>

                {/* Selected Medications */}
                <div className="space-y-2">
                  <p className="text-sm font-medium">Médicaments sélectionnés</p>
                  {medications.filter((_: any, index: number) => {
                    const key = `${medications[index].name}-${index}`;
                    return selectedMedications[key];
                  }).length > 0 ? (
                    medications.map((med: Medication, index: number) => {
                      const key = `${med.name}-${index}`;
                      if (!selectedMedications[key]) return null;

                      return (
                        <div key={index} className="flex justify-between text-sm">
                          <span className="truncate flex-1 pr-2">{med.name}</span>
                          <span className="font-medium">{med.price?.toLocaleString()} FCFA</span>
                        </div>
                      );
                    })
                  ) : (
                    <p className="text-sm text-gray-500 italic">Aucun médicament sélectionné</p>
                  )}
                </div>

                {/* Price Breakdown */}
                <div className="space-y-2 pt-4 border-t">
                  <div className="flex justify-between text-sm">
                    <span>Sous-total médicaments</span>
                    <span>{subtotal.toLocaleString()} FCFA</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span>Frais de livraison</span>
                    <span>{deliveryFee.toLocaleString()} FCFA</span>
                  </div>
                  <div className="flex justify-between text-lg font-bold border-t pt-2">
                    <span>Total à payer</span>
                    <span className="text-blue-600">{grandTotal.toLocaleString()} FCFA</span>
                  </div>
                </div>

                {/* Action Buttons */}
                <div className="space-y-2 pt-4">
                  <Button
                    onClick={() => setShowPaymentModal(true)}
                    disabled={subtotal === 0}
                    className="w-full bg-green-600 hover:bg-green-700"
                  >
                    <CreditCard className="h-4 w-4 mr-2" />
                    Procéder au paiement
                  </Button>

                  <Button
                    onClick={handleCancelOrder}
                    variant="destructive"
                    className="w-full"
                    disabled={cancelOrderMutation.isPending}
                  >
                    <X className="h-4 w-4 mr-2" />
                    Annuler la commande
                  </Button>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

      {/* Payment Modal */}
      {showPaymentModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg max-w-md w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold">💳 Paiement</h3>
                <Button 
                  variant="ghost" 
                  size="sm"
                  onClick={() => setShowPaymentModal(false)}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              <div className="space-y-4">
                {/* Payment Summary */}
                <div className="bg-gray-50 rounded-lg p-4">
                  <h4 className="font-medium mb-2">Récapitulatif du paiement</h4>
                  <div className="space-y-1 text-sm">
                    <div className="flex justify-between">
                      <span>Médicaments:</span>
                      <span>{subtotal.toLocaleString()} FCFA</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Livraison:</span>
                      <span>{deliveryFee.toLocaleString()} FCFA</span>
                    </div>
                    <div className="flex justify-between font-semibold border-t pt-1">
                      <span>Total:</span>
                      <span>{grandTotal.toLocaleString()} FCFA</span>
                    </div>
                  </div>
                </div>

                {/* Payment Methods */}
                <div>
                  <h4 className="font-medium mb-3">Choisir le moyen de paiement</h4>
                  <div className="space-y-2">
                    {getPaymentMethods().map((method) => (
                      <div 
                        key={method.id}
                        className={`border rounded-lg p-3 cursor-pointer transition-colors ${
                          paymentMethod === method.id 
                            ? 'border-blue-500 bg-blue-50' 
                            : 'border-gray-200 hover:border-gray-300'
                        }`}
                        onClick={() => setPaymentMethod(method.id)}
                      >
                        <div className="flex items-center gap-3">
                          <div className={`w-4 h-4 rounded-full border-2 ${
                            paymentMethod === method.id 
                              ? 'border-blue-500 bg-blue-500' 
                              : 'border-gray-300'
                          }`}>
                            {paymentMethod === method.id && (
                              <div className="w-full h-full rounded-full bg-white scale-50"></div>
                            )}
                          </div>
                          <div>
                            <p className="font-medium">{method.name}</p>
                            <p className="text-sm text-gray-600">{method.number}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Payment Instructions */}
                {paymentMethod && (
                  <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                    <h4 className="font-medium mb-2">📋 Instructions</h4>
                    <div className="text-sm text-yellow-800 space-y-1">
                      <p>1. Ouvrez votre app {getPaymentMethods().find(m => m.id === paymentMethod)?.name}</p>
                      <p>2. Envoyez <strong>{grandTotal.toLocaleString()} FCFA</strong> au numéro:</p>
                      <p className="font-bold">{getPaymentMethods().find(m => m.id === paymentMethod)?.number}</p>
                      <p>3. Confirmez ci-dessous une fois le paiement effectué</p>
                    </div>
                  </div>
                )}

                {/* Action Buttons */}
                <div className="flex gap-3">
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => setShowPaymentModal(false)}
                  >
                    Annuler
                  </Button>
                  <Button
                    className="flex-1"
                    onClick={handlePayment}
                    disabled={!paymentMethod || paymentMutation.isPending}
                  >
                    {paymentMutation.isPending ? 'Traitement...' : 'Confirmer'}
                  </Button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

client/src/pages/order.tsx.content:
import { useState, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { apiRequest } from "@/lib/queryClient";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { useLocation } from "wouter";
import BottomNavigation from "@/components/bottom-navigation";
import { Camera, Upload, Plus, X, FileText, ArrowLeft, MapPin, Phone, Star, Clock } from "lucide-react";

export default function OrderPage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [location, navigate] = useLocation();

  // Get pharmacy data from URL params or localStorage
  const [selectedPharmacy, setSelectedPharmacy] = useState<any>(null);

  const [orderData, setOrderData] = useState({
    deliveryAddress: '',
    deliveryLatitude: null as number | null,
    deliveryLongitude: null as number | null,
    medications: [{ name: '', surBon: false }],
    pharmacyMessage: '',
    bonDocuments: [] as File[],
    prescriptionPhoto: null as File | null
  });

  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [currentAddress, setCurrentAddress] = useState<string>("");
  const [isDetectingLocation, setIsDetectingLocation] = useState(false);

  useEffect(() => {
    // Try to get pharmacy data from localStorage (set when navigating from pharmacy list)
    const pharmacyData = localStorage.getItem('selectedPharmacy');
    if (pharmacyData) {
      setSelectedPharmacy(JSON.parse(pharmacyData));
      // Clear it after use
      localStorage.removeItem('selectedPharmacy');
    } else {
      // If no pharmacy selected, redirect back to pharmacies
      navigate('/pharmacies');
    }
  }, [navigate]);

  // Géolocalisation automatique
  useEffect(() => {
    if (navigator.geolocation) {
      setIsDetectingLocation(true);
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const { latitude, longitude } = position.coords;
          setUserLocation({ lat: latitude, lng: longitude });
          setOrderData(prev => ({
            ...prev,
            deliveryLatitude: latitude,
            deliveryLongitude: longitude
          }));

          // Reverse geocoding pour obtenir l'adresse
          try {
            const response = await fetch(`/api/location/reverse?lat=${latitude}&lng=${longitude}`);
            const addressData = await response.json();
            setCurrentAddress(addressData.formatted_address);
            setOrderData(prev => ({ ...prev, deliveryAddress: addressData.formatted_address }));

            toast({
              title: "Position détectée",
              description: "Votre adresse a été automatiquement remplie.",
            });
          } catch (error) {
            console.error("Erreur géolocalisation:", error);
          } finally {
            setIsDetectingLocation(false);
          }
        },
        (error) => {
          console.error("Erreur de géolocalisation:", error);
          setIsDetectingLocation(false);
          toast({
            title: "Géolocalisation",
            description: "Impossible d'obtenir votre position. Veuillez saisir votre adresse manuellement.",
            variant: "destructive",
          });
        },
        {
          enableHighAccuracy: true,
          timeout: 10000,
          maximumAge: 300000
        }
      );
    }
  }, [toast]);

  // Helper functions for medication management
  const addMedication = () => {
    setOrderData(prev => ({
      ...prev,
      medications: [...prev.medications, { name: '', surBon: false }]
    }));
  };

  const removeMedication = (index: number) => {
    setOrderData(prev => ({
      ...prev,
      medications: prev.medications.filter((_, i) => i !== index)
    }));
  };

  const updateMedication = (index: number, field: 'name' | 'surBon', value: string | boolean) => {
    setOrderData(prev => ({
      ...prev,
      medications: prev.medications.map((med, i) => 
        i === index ? { ...med, [field]: value } : med
      )
    }));
  };

  const handlePrescriptionPhoto = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setOrderData(prev => ({ ...prev, prescriptionPhoto: file }));
      toast({
        title: "Photo capturée",
        description: "Photo d'ordonnance ajoutée avec succès",
      });
      // Vider l'input pour permettre la reprise de la même photo
      e.target.value = '';
    }
  };

  const removePrescriptionPhoto = () => {
    setOrderData(prev => ({ ...prev, prescriptionPhoto: null }));
  };

  const triggerCameraInput = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }
    const input = document.getElementById('camera-input') as HTMLInputElement;
    if (input) {
      input.click();
    }
  };

  const handleDocumentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    setOrderData(prev => ({ ...prev, bonDocuments: [...prev.bonDocuments, ...files] }));
  };

  const removeDocument = (index: number) => {
    setOrderData(prev => ({
      ...prev,
      bonDocuments: prev.bonDocuments.filter((_, i) => i !== index)
    }));
  };

  const createOrderMutation = useMutation({
    mutationFn: async (orderData: any) => {
      const formData = new FormData();
      formData.append('pharmacyId', selectedPharmacy.id);
      formData.append('deliveryAddress', orderData.deliveryAddress);
      formData.append('deliveryNotes', orderData.pharmacyMessage || '');
      formData.append('medications', JSON.stringify(orderData.medications));
      formData.append('status', 'pending');

      // Ajouter les coordonnées de géolocalisation
      if (orderData.deliveryLatitude) {
        formData.append('deliveryLatitude', orderData.deliveryLatitude.toString());
      }
      if (orderData.deliveryLongitude) {
        formData.append('deliveryLongitude', orderData.deliveryLongitude.toString());
      }

      if (orderData.prescriptionPhoto) {
        formData.append('prescriptionPhoto', orderData.prescriptionPhoto);
      }

      orderData.bonDocuments.forEach((file: File, index: number) => {
        formData.append(`bonDocument${index}`, file);
      });

      const response = await fetch('/api/orders', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Failed to create order');
      }

      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Commande envoyée",
        description: "Votre commande a été envoyée à la pharmacie avec succès!",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/orders'] });
      navigate('/dashboard-patient');
    },
    onError: (error: any) => {
      toast({
        variant: "destructive",
        title: "Erreur",
        description: error.message || "Une erreur est survenue lors de l'envoi de la commande",
      });
    },
  });

  const handleCreateOrder = () => {
    if (!selectedPharmacy) {
      toast({
        variant: "destructive",
        title: "Pharmacie requise",
        description: "Aucune pharmacie sélectionnée",
      });
      return;
    }

    if (!orderData.deliveryAddress.trim()) {
      toast({
        variant: "destructive",
        title: "Adresse requise",
        description: "Veuillez saisir votre adresse de livraison",
      });
      return;
    }

    if (!orderData.medications.some(med => med.name.trim())) {
      toast({
        variant: "destructive",
        title: "Médicaments requis",
        description: "Veuillez ajouter au moins un médicament",
      });
      return;
    }

    if (!orderData.prescriptionPhoto) {
      toast({
        variant: "destructive",
        title: "Photo d'ordonnance requise",
        description: "Veuillez ajouter une photo de votre ordonnance",
      });
      return;
    }

    // Vérifier si des documents BON sont requis
    const validMedications = orderData.medications.filter(med => med.name.trim());
    const hasBonMedications = validMedications.some(med => med.surBon);

    if (hasBonMedications && orderData.bonDocuments.length === 0) {
      toast({
        variant: "destructive",
        title: "Documents BON requis",
        description: "Vous avez des médicaments sur BON, veuillez ajouter les documents nécessaires",
      });
      return;
    }

    // Include pharmacy ID in the order data
    const orderPayload = {
      ...orderData,
      pharmacyId: selectedPharmacy.id,
      medications: validMedications,
      status: 'pending'
    };

    createOrderMutation.mutate(orderPayload);
  };

  if (!selectedPharmacy) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p>Chargement...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-4xl mx-auto p-4 pb-20">
        {/* Header */}
        <div className="flex items-center gap-4 mb-6">
          <Button 
            variant="ghost" 
            size="sm" 
            onClick={() => navigate('/pharmacies')}
            className="flex items-center gap-2"
          >
            <ArrowLeft className="h-4 w-4" />
            Retour
          </Button>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">
              Nouvelle Commande
            </h1>
            <p className="text-gray-600">
              Commande à {selectedPharmacy.name}
            </p>
          </div>
        </div>

        {/* Pharmacy Info Card */}
        <Card className="mb-6 border-l-4 border-l-blue-500">
          <CardContent className="p-4">
            <div className="flex items-start justify-between mb-3">
              <div className="flex-1">
                <h4 className="font-semibold text-lg">{selectedPharmacy.name}</h4>
                <p className="text-sm text-gray-600 flex items-center gap-1 mt-1">
                  <MapPin className="h-3 w-3" />
                  {selectedPharmacy.address}
                </p>
                <p className="text-sm text-gray-500 flex items-center gap-1 mt-1">
                  <Phone className="h-3 w-3" />
                  {selectedPharmacy.phone}
                </p>
              </div>
              <div className="flex flex-col items-end gap-1">
                <div className="flex items-center gap-4 text-sm">
                  <span className="flex items-center gap-1">
                    <Star className="h-3 w-3 text-yellow-500" />
                    {selectedPharmacy.rating}/5
                  </span>
                  <span className="flex items-center gap-1">
                    <Clock className="h-3 w-3" />
                    {selectedPharmacy.deliveryTime} min
                  </span>
                </div>
              </div>
            </div>
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
              <p className="text-sm text-blue-800">
                💰 Frais de livraison: 1000 FCFA (500 FCFA plateforme + 500 FCFA livreur)
              </p>
            </div>
          </CardContent>
        </Card>

        {/* Order Form */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">
              📋 Détails de la Commande
            </CardTitle>
            <CardDescription>
              Remplissez les informations nécessaires pour votre commande
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Photo de l'ordonnance */}
            <div>
              <label className="block text-sm font-medium mb-3">Photo de l'ordonnance *</label>
              <div className="space-y-3">
                {!orderData.prescriptionPhoto ? (
                  <div className="border-2 border-dashed border-blue-300 rounded-lg p-6 bg-blue-50">
                    <div className="text-center">
                      <Camera className="mx-auto h-16 w-16 text-blue-500 mb-3" />
                      <div className="text-lg font-medium text-blue-900 mb-2">
                        Envoyer la photo de l'ordonnance
                      </div>
                      <div className="text-sm text-blue-700 mb-4">
                        Prenez une photo claire de votre ordonnance en format portrait
                      </div>
                      <div>
                        <input
                          type="file"
                          accept="image/*"
                          onChange={handlePrescriptionPhoto}
                          className="hidden"
                          id="camera-input"
                        />
                        <Button 
                          type="button" 
                          className="bg-blue-600 hover:bg-blue-700 w-full"
                          onClick={(e) => triggerCameraInput(e)}
                        >
                          <Camera className="h-4 w-4 mr-2" />
                          Prendre une photo
                        </Button>
                      </div>
                      <div className="text-xs text-blue-600 mt-2">
                        Formats acceptés: PNG, JPEG, JPG
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="border border-green-200 rounded-lg p-4 bg-green-50">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center">
                          <Camera className="h-6 w-6 text-green-600" />
                        </div>
                        <div>
                          <p className="font-medium text-green-900">Photo ajoutée</p>
                          <p className="text-sm text-green-700 truncate max-w-48">{orderData.prescriptionPhoto.name}</p>
                        </div>
                      </div>
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        onClick={removePrescriptionPhoto}
                        className="text-red-600 hover:text-red-700 hover:bg-red-50"
                      >
                        <X className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Adresse de livraison */}
            <div>
              <label className="block text-sm font-medium mb-2">Adresse de livraison *</label>

              {/* Zone d'affichage de la géolocalisation */}
              {isDetectingLocation && (
                <div className="mb-3 p-3 bg-blue-50 border border-blue-200 rounded-lg">
                  <div className="flex items-center gap-2">
                    <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-blue-700 text-sm">Détection de votre position...</span>
                  </div>
                </div>
              )}

              {userLocation && (
                <div className="mb-3 p-3 bg-green-50 border border-green-200 rounded-lg">
                  <div className="flex items-start justify-between">
                    <div className="flex items-start gap-2">
                      <MapPin className="h-4 w-4 text-green-600 mt-0.5 flex-shrink-0" />
                      <div>
                        <p className="text-green-700 text-sm font-medium">Position détectée</p>
                        <p className="text-green-600 text-xs">
                          📍 {userLocation.lat.toFixed(6)}, {userLocation.lng.toFixed(6)}
                        </p>
                        {currentAddress && (
                          <p className="text-green-600 text-xs mt-1">{currentAddress}</p>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              )}

              <Input
                type="text"
                placeholder="Saisissez votre adresse complète"
                value={orderData.deliveryAddress}
                onChange={(e) => setOrderData(prev => ({ ...prev, deliveryAddress: e.target.value }))}
                className="w-full"
              />
              <p className="text-xs text-gray-500 mt-1">
                L'adresse sera automatiquement remplie si la géolocalisation est autorisée
              </p>
            </div>

            {/* Liste des médicaments */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <label className="block text-sm font-medium">Médicaments souhaités *</label>
                <Button 
                  type="button" 
                  variant="outline" 
                  size="sm" 
                  onClick={addMedication}
                  className="flex items-center gap-1"
                >
                  <Plus className="h-4 w-4" />
                  Ajouter
                </Button>
              </div>
              <div className="space-y-3">
                {orderData.medications.map((medication, index) => (
                  <div key={index} className="flex items-center gap-3 p-3 border border-gray-200 rounded-lg">
                    <div className="flex-1">
                      <Input
                        type="text"
                        placeholder="Nom du médicament"
                        value={medication.name}
                        onChange={(e) => updateMedication(index, 'name', e.target.value)}
                        className="w-full"
                      />
                    </div>
                    <div className="flex items-center space-x-2">
                      <Switch
                        id={`sur-bon-${index}`}
                        checked={medication.surBon}
                        onCheckedChange={(checked) => updateMedication(index, 'surBon', checked)}
                      />
                      <Label 
                        htmlFor={`sur-bon-${index}`} 
                        className={`text-sm font-medium ${
                          medication.surBon ? 'text-green-600' : 'text-gray-600'
                        }`}
                      >
                        Sur BON
                      </Label>
                    </div>
                    {orderData.medications.length > 1 && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        onClick={() => removeMedication(index)}
                        className="text-red-600 hover:text-red-800 p-1"
                      >
                        <X className="h-4 w-4" />
                      </Button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Documents pour BON - conditionnel */}
            {(() => {
              const hasBonMedications = orderData.medications.some(med => med.name.trim() && med.surBon);
              if (!hasBonMedications) return null;

              return (
                <div>
                  <label className="block text-sm font-medium mb-2">
                    Documents pour validation BON *
                    <span className="text-orange-600 text-xs ml-2">
                      (Requis car vous avez des médicaments sur BON)
                    </span>
                  </label>
                  <div className="border-2 border-dashed border-orange-300 rounded-lg p-4 bg-orange-50">
                    <div className="text-center">
                      <FileText className="mx-auto h-8 w-8 text-orange-500 mb-2" />
                      <p className="text-sm text-orange-800 mb-2 font-medium">
                        Documents obligatoires pour validation BON
                      </p>
                      <p className="text-xs text-orange-700 mb-3">
                        Carte d'assurance, attestation de prise en charge, etc.
                      </p>
                      <input
                        type="file"
                        multiple
                        accept="image/*,.pdf"
                        onChange={handleDocumentUpload}
                        className="hidden"
                        id="bon-documents-input"
                      />
                      <Button 
                        type="button" 
                        className="bg-orange-600 hover:bg-orange-700 text-white"
                        size="sm"
                        onClick={() => document.getElementById('bon-documents-input')?.click()}
                      >
                        <Upload className="h-4 w-4 mr-2" />
                        Choisir des fichiers
                      </Button>
                    </div>
                    {orderData.bonDocuments.length > 0 && (
                      <div className="mt-4 space-y-2">
                        {orderData.bonDocuments.map((doc, index) => (
                          <div key={index} className="flex items-center justify-between p-2 bg-white rounded border border-orange-200">
                            <div className="flex items-center gap-2">
                              <FileText className="h-4 w-4 text-orange-600" />
                              <span className="text-sm text-gray-700">{doc.name}</span>
                            </div>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => removeDocument(index)}
                              className="text-red-600 hover:text-red-800 p-1"
                            >
                              <X className="h-4 w-4" />
                            </Button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              );
            })()}

            {/* Message à la pharmacie */}
            <div>
              <label className="block text-sm font-medium mb-2">Message à la pharmacie</label>
              <Textarea
                placeholder="Informations complémentaires, questions spécifiques..."
                value={orderData.pharmacyMessage}
                onChange={(e) => setOrderData(prev => ({ ...prev, pharmacyMessage: e.target.value }))}
                className="w-full"
                rows={3}
              />
            </div>

            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <p className="text-sm text-blue-800">
                💡 <strong>Info:</strong> La photo d'ordonnance est obligatoire pour confirmer votre commande. 
                La pharmacie déterminera le prix final en fonction des médicaments disponibles. 
                Les médicaments marqués "Sur BON" nécessitent une validation de vos documents d'assurance.
              </p>
            </div>

            <div className="pt-4">
              <Button
                onClick={handleCreateOrder}
                disabled={createOrderMutation.isPending || !orderData.deliveryAddress || !orderData.medications.some(med => med.name.trim()) || !orderData.prescriptionPhoto}
                className="w-full bg-blue-600 hover:bg-blue-700"
              >
                {createOrderMutation.isPending ? "Envoi en cours..." : "📤 Confirmer la commande"}
              </Button>

              {/* Indicateur de validation */}
              <div className="mt-2 text-xs text-gray-500 text-center">
                {!orderData.prescriptionPhoto && (
                  <span className="text-red-600">⚠️ Photo d'ordonnance requise</span>
                )}
                {orderData.prescriptionPhoto && orderData.medications.some(med => med.name.trim() && med.surBon) && orderData.bonDocuments.length === 0 && (
                  <span className="text-orange-600">⚠️ Documents BON requis</span>
                )}
                {orderData.prescriptionPhoto && (!orderData.medications.some(med => med.name.trim() && med.surBon) || orderData.bonDocuments.length > 0) && (
                  <span className="text-green-600">✅ Prêt à confirmer</span>
                )}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <BottomNavigation currentPage="pharmacies" />
    </div>
  );
}

